void FileFilterIndex::setTextFilter(const std::string text)
{
	mTextFilter = Utils::String::toUpper(text);
}

bool FileFilterIndex::showFile(FileData* game)
{
	// this shouldn't happen, but just in case let's get it out of the way
	if (!isFiltered())
		return true;

	// if folder, needs further inspection - i.e. see if folder contains at least one element
	// that should be shown
	if (game->getType() == FOLDER) 
	{
		std::vector<FileData*> children = ((FolderData*) game)->getChildren();
		// iterate through all of the children, until there's a match

		for (std::vector<FileData*>::const_iterator it = children.cbegin(); it != children.cend(); ++it ) {
			if (showFile(*it))
				return true;
		}
		return false;
	}

	bool keepGoing = false;

    if (!mTextFilter.empty() && matchPinyinAndEnglishFirstLetters(game->getName(), mTextFilter)) {
        keepGoing = true;
    }


	for (std::vector<FilterDataDecl>::const_iterator it = filterDataDecl.cbegin(); it != filterDataDecl.cend(); ++it ) {
		FilterDataDecl filterData = (*it);
		if(*(filterData.filteredByRef))
		{
			// try to find a match
			std::string key = getIndexableKey(game, filterData.type, false);
			keepGoing = isKeyBeingFilteredBy(key, filterData.type);

			// if we didn't find a match, try for secondary keys - i.e. publisher and dev, or first genre
			if (!keepGoing)
			{
				if (!filterData.hasSecondaryKey)
				{
					return false;
				}
				std::string secKey = getIndexableKey(game, filterData.type, true);
				if (secKey != UNKNOWN_LABEL)
				{
					keepGoing = isKeyBeingFilteredBy(secKey, filterData.type);
				}
			}
			// if still nothing, then it's not a match
			if (!keepGoing)
				return false;

		}

	}

	return keepGoing;
}

char FileFilterIndex::getPinyinFirstLetter(const std::string& pinyin) {
    // 假设拼音首字母为拼音字符串的第一个字符的小写字母
    return std::tolower(pinyin[0]);
}

// 工具函数：将字符串转为大写
std::string FileFilterIndex::toUpper(const std::string &str) {
    std::string result = str;
    std::transform(result.begin(), result.end(), result.begin(), ::toupper);
    return result;
}

// 工具函数：获取英文字符的首字母（如果是英文字符）
char FileFilterIndex::getEnglishFirstLetter(char ch) {
    if (std::isalpha(ch)) {
        return std::tolower(ch);
    }
    return '\0'; // 非英文字符返回空字符
}

// 检查游戏名称是否包含指定拼音首字母或英文首字母
bool FileFilterIndex::matchPinyinAndEnglishFirstLetters(const std::string& gameName, const std::string& mTextFilter) {
    std::string concatenatedFirstLetters;

    for (size_t i = 0; i < gameName.size(); ++i) {
        unsigned char c = gameName[i];

        if ((c & 0x80) == 0) {
            // English character (ASCII)
            char englishFirstLetter = getEnglishFirstLetter(c);
            if (englishFirstLetter != '\0') {
                concatenatedFirstLetters += englishFirstLetter;
            }
        } else {
            // Assuming this is a multi-byte character (UTF-8 encoded Chinese character)
            // We would typically need to decode the UTF-8 character, for simplicity,
            // assume this is a valid UTF-8 encoded Chinese character

            // Handle the Chinese characters, we can use a mapping like pinyin_map
            wchar_t wc = static_cast<wchar_t>(c); // Simplified for example
            if (pinyin_map.find(wc) != pinyin_map.end()) {
                const std::vector<std::string>& pinyinList = pinyin_map[wc];
                for (const std::string& pinyin : pinyinList) {
                    concatenatedFirstLetters += getPinyinFirstLetter(pinyin);
                }
            }
        }
    }

    // 转换拼音首字母串为大写，并与 mTextFilter 比较
    return toUpper(concatenatedFirstLetters).find(toUpper(mTextFilter)) != std::string::npos;
}


bool FileFilterIndex::isKeyBeingFilteredBy(std::string key, FilterIndexType type)
{
	const FilterIndexType filterTypes[6] = { FAVORITES_FILTER, GENRE_FILTER, PLAYER_FILTER, PUBDEV_FILTER, RATINGS_FILTER, KIDGAME_FILTER }; // ,HIDDEN_FILTER
	std::vector<std::string> filterKeysList[6] = { favoritesIndexFilteredKeys, genreIndexFilteredKeys, playersIndexFilteredKeys, pubDevIndexFilteredKeys, ratingsIndexFilteredKeys, kidGameIndexFilteredKeys }; // hiddenIndexFilteredKeys, 

	for (int i = 0; i < 6; i++)
	{
		if (filterTypes[i] == type)
		{
			for (std::vector<std::string>::const_iterator it = filterKeysList[i].cbegin(); it != filterKeysList[i].cend(); ++it )
			{
				if (key == (*it))
				{
					return true;
				}
			}
			return false;
		}
	}

	return false;
}

void FileFilterIndex::manageGenreEntryInIndex(FileData* game, bool remove)
{

	std::string key = getIndexableKey(game, GENRE_FILTER, false);

	// flag for including unknowns
	bool includeUnknown = INCLUDE_UNKNOWN;

	// only add unknown in pubdev IF both dev and pub are empty
	if (!includeUnknown && (key == UNKNOWN_LABEL || key == "BIOS")) {
		// no valid genre info found
		return;
	}

	manageIndexEntry(&genreIndexAllKeys, key, remove);

	key = getIndexableKey(game, GENRE_FILTER, true);
	if (!includeUnknown && key == UNKNOWN_LABEL)
	{
		manageIndexEntry(&genreIndexAllKeys, key, remove);
	}
}

void FileFilterIndex::managePlayerEntryInIndex(FileData* game, bool remove)
{
	// flag for including unknowns
	bool includeUnknown = INCLUDE_UNKNOWN;
	std::string key = getIndexableKey(game, PLAYER_FILTER, false);

	// only add unknown in pubdev IF both dev and pub are empty
	if (!includeUnknown && key == UNKNOWN_LABEL) {
		// no valid player info found
		return;
	}

	manageIndexEntry(&playersIndexAllKeys, key, remove);
}

void FileFilterIndex::managePubDevEntryInIndex(FileData* game, bool remove)
{
	std::string pub = getIndexableKey(game, PUBDEV_FILTER, false);
	std::string dev = getIndexableKey(game, PUBDEV_FILTER, true);

	// flag for including unknowns
	bool includeUnknown = INCLUDE_UNKNOWN;
	bool unknownPub = false;
	bool unknownDev = false;

	if (pub == UNKNOWN_LABEL) {
		unknownPub = true;
	}
	if (dev == UNKNOWN_LABEL) {
		unknownDev = true;
	}

	if (!includeUnknown && unknownDev && unknownPub) {
		// no valid rating info found
		return;
	}

	if (unknownDev && unknownPub) {
		// if no info at all
		manageIndexEntry(&pubDevIndexAllKeys, pub, remove);
	}
	else
	{
		if (!unknownDev) {
			// if no info at all
			manageIndexEntry(&pubDevIndexAllKeys, dev, remove);
		}
		if (!unknownPub) {
			// if no info at all
			manageIndexEntry(&pubDevIndexAllKeys, pub, remove);
		}
	}
}

void FileFilterIndex::manageRatingsEntryInIndex(FileData* game, bool remove)
{
	std::string key = getIndexableKey(game, RATINGS_FILTER, false);

	// flag for including unknowns
	bool includeUnknown = INCLUDE_UNKNOWN;

	if (!includeUnknown && key == UNKNOWN_LABEL) {
		// no valid rating info found
		return;
	}

	manageIndexEntry(&ratingsIndexAllKeys, key, remove);
}

